import React, { useState, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Button, StatusBadge, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { gtService } from '../../../services/gt/gtService';
import type { CostSheetDto, CostElementDto } from '../../../services/gt/models';
import { formatVnd } from '../../../utils/formatters';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import erp from '../../../styles/erpPage.module.css';

const GiaThanhDetailPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const dispatch = useAppDispatch();
  const [sheet, setSheet] = useState<CostSheetDto | null>(null);
  const [elements, setElements] = useState<CostElementDto[]>([]);
  const [loading, setLoading] = useState(false);
  const [acting, setActing] = useState(false);

  const load = useCallback(() => {
    if (!id) return;
    setLoading(true);
    Promise.all([gtService.getCostSheet(id), gtService.getCostElements(id)])
      .then(([s, els]) => { setSheet(s); setElements(els); })
      .catch(err => dispatch(addToast({ message: getApiErrorMessage(err, 'Lỗi tải chi tiết'), type: 'error' })))
      .finally(() => setLoading(false));
  }, [id, dispatch]);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => { if (!cancelled) load(); }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [load]);

  const handleCalculate = async () => {
    if (!sheet) return;
    setActing(true);
    try {
      await gtService.calculateCosts(sheet.month, sheet.year);
      dispatch(addToast({ message: 'Tính giá thành thành công', type: 'success' }));
      load();
    } catch (e: unknown) {
      dispatch(addToast({ message: getApiErrorMessage(e, 'Lỗi tính giá thành'), type: 'error' }));
    } finally {
      setActing(false);
    }
  };

  const handleApprove = async () => {
    if (!id) return;
    setActing(true);
    try {
      await gtService.approveCostSheet(id);
      dispatch(addToast({ message: 'Duyệt giá thành thành công', type: 'success' }));
      load();
    } catch (e: unknown) {
      dispatch(addToast({ message: getApiErrorMessage(e, 'Lỗi duyệt giá thành'), type: 'error' }));
    } finally {
      setActing(false);
    }
  };

  const handlePost = async () => {
    if (!id) return;
    setActing(true);
    try {
      await gtService.postCostSheet(id);
      dispatch(addToast({ message: 'Ghi sổ giá thành thành công', type: 'success' }));
      load();
    } catch (e: unknown) {
      dispatch(addToast({ message: getApiErrorMessage(e, 'Lỗi ghi sổ giá thành'), type: 'error' }));
    } finally {
      setActing(false);
    }
  };

  if (loading) return <div className={erp.loading} data-testid="erp-gia-thanh-detail-loading">Đang tải...</div>;
  if (!sheet) {
    return (
      <div className={erp.page} data-testid="erp-gia-thanh-detail-empty">
        <div className={erp.pageHeader}>
          <button type="button" className={erp.codeLink} onClick={() => navigate('/gt/gia-thanh')}>← Quay lại</button>
        </div>
        <div className={erp.empty}>Không tìm thấy bảng giá thành</div>
      </div>
    );
  }

  const status = sheet.status ?? 'Draft';
  const canCalculate = status === 'Draft';
  const canApprove = status === 'Draft' || status === 'Calculated';
  const canPost = status === 'Approved';

  return (
    <div className={erp.page} data-testid="erp-gia-thanh-detail">
      <div className={erp.pageHeader}>
        <div className={erp.titleBlock}>
          <button type="button" className={erp.codeLink} onClick={() => navigate('/gt/gia-thanh')}>← Quay lại</button>
          <h1 className={erp.title}>Giá thành — {sheet.code} <StatusBadge status={sheet.status} /></h1>
        </div>
        <div className={erp.headerActions}>
          {canCalculate && (
            <Button
              variant="secondary"
              disabled={acting}
              onClick={handleCalculate}
              data-testid="erp-gia-thanh-calculate"
            >
              Tính giá thành
            </Button>
          )}
          {canApprove && (
            <Button
              variant="secondary"
              disabled={acting}
              onClick={handleApprove}
              data-testid="erp-gia-thanh-approve"
            >
              Duyệt
            </Button>
          )}
          {canPost && (
            <Button
              variant="primary"
              disabled={acting}
              onClick={handlePost}
              data-testid="erp-gia-thanh-post"
            >
              Ghi sổ
            </Button>
          )}
        </div>
      </div>
      <div className={erp.summaryBar}>
        <div className={erp.summaryItem}><label className={erp.label}>Sản phẩm</label><strong>{sheet.productName ?? sheet.productCode}</strong></div>
        <div className={erp.summaryItem}><label className={erp.label}>Kỳ</label><strong>{sheet.month}/{sheet.year}</strong></div>
        <div className={erp.summaryItem}><label className={erp.label}>SL thực tế</label><strong>{sheet.actualQty}</strong></div>
        <div className={erp.summaryItem}><label className={erp.label}>Tổng giá thành</label><strong>{formatVnd(sheet.totalCost)}</strong></div>
        <div className={erp.summaryItem}><label className={erp.label}>Giá thành ĐV</label><strong>{formatVnd(sheet.unitCost)}</strong></div>
      </div>
      <div className={erp.tableCard} data-testid="erp-gia-thanh-elements-table">
        <div className={erp.tableWrapper}>
          <table className={erp.table}>
            <thead><tr><th>Loại YT</th><th>Diễn giải</th><th>TK</th><th className={erp.colRight}>Số tiền</th></tr></thead>
            <tbody>{elements.map((el, i) => (
              <tr key={el.id ?? i}>
                <td>{el.elementType}</td>
                <td>{el.description}</td>
                <td><code>{el.accountCode}</code></td>
                <td className={erp.colRight}>{formatVnd(el.amount)}</td>
              </tr>
            ))}</tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default GiaThanhDetailPage;
